const { SlashCommandBuilder } = require('@discordjs/builders');
const { Client, Intents } = require('discord.js');

const client = new Client({
  intents: [Intents.FLAGS.Guilds, Intents.FLAGS.GuildMessages],
});

const banCommand = new SlashCommandBuilder()
  .setName('ban')
  .setDescription('Bans a user from the server')
  .addUserOption(option => option.setName('user').setDescription('The user to ban'))
  .addUserOption(option => option.setName('days').setDescription('The number of days to ban the user for'));

client.on('ready', async () => {
  console.log(`Logged in as ${client.user.tag}`);
});

client.on('interactionCreate', async interaction => {
  if (interaction.isCommand()) {
    const { data: command } = await interaction.getCommand();
    if (command.name === 'ban') {
      const user = interaction.options.getUser('user');
      const days = interaction.options.getInteger('days');
      if (user && days) {
        const member = interaction.guild.members.cache.get(user.id);
        if (member) {
          await member.ban({ days });
          await interaction.reply({
            content: `User ${user.username} has been banned for ${days} days`,
            ephemeral: true,
          });
        } else {
          await interaction.reply({
            content: `User ${user.username} not found`,
            ephemeral: true,
          });
        }
      } else {
        await interaction.reply({
          content: "You need to specify a user and the number of days to ban them for",
          ephemeral: true,
        });
      }
    }
  }
});

client.login('YOUR_DISCORD_BOT_TOKEN_HERE');
